<template>
  <div class="padding-t_10" id="reportstabsdata">
    <div class="left-menu-tab new_tab">
      <div class="col-md-12 p-0">
        <div class="theme-primary partition">
          <span class="p-name text-white">{{ $t("SilentAppReports") }}</span>
        </div>
      </div>
      <div class="pt-2 mb-1 w-100 d-none d-lg-block">
        <div class="input-group customsearchbox">
          <input type="text" maxlength="50" :placeholder="$t('Search')" class="form-control searchcustomfilter border-right-0"
            autocomplete="off" v-model="searchQuery" />
          <div class="input-group-append">
            <span class="input-group-text bg-transparent bg-white border-left-0"><i class="fa fa-search"></i></span>
          </div>
        </div>
      </div>
      <div class="mt-2" id="divscrollsetuptabs" style="max-height: 700px">
        <ul class="nav nav-pills flex-column left-tab responivecustomtab lefttabiconfix lefttabflexible" id="upper"
          role="tablist">
          <li v-for="(tab, index) in filteredTabs" :key="index">
            <a class="nav-link left-menu" :data-toggle="'#' + tab.id" :class="{ active: activeKey === tab.index }"
              @click="activateTab(tab.index)">
              <i :class="tab.icon" aria-hidden="true"></i>&nbsp;
              {{ $t(tab.name) }}
            </a>
          </li>
        </ul>
      </div>
    </div>

    <!-- right-content here -->
    <div class="right-content">
      <div class="col-md-12 p-0">
        <div class="theme-primary partition p-actions-expand d-flex row" style="overflow: visible">
          <div class="action-headings col-md-7">
            <span class="p-name text-white" id="spnreporttext">{{
              this.$t(activeTabName)
            }}</span>
            <span class="p-actions float-right">
              <a href="javascript:;" id="ancshowmorefilter" class="p-action-btn text-white" style="display: none"
                :title="$t('Show') + ' ' + $t('More') + ' ' + $t('Filter')">
                <i class="fa fa-filter" aria-hidden="true"></i><br />{{
                  $t("Show")
                }}
                {{ $t("More") }} {{ $t("Filter") }}
              </a>
            </span>

            <span class="collapse-head-btns">
              <a href="javascript:;" class="collapse-btns"><i class="fa fa-angle-up text-white"></i></a>
            </span>
          </div>
          <div class="col-md-5">
            <div class="row customCol align-items-center justify-content-end align-items-center"
              style="padding: 5px 0;">
              <DateRangeSelector 
                :date-span="dateSpan"
                :from-date="monthStartDate"
                :to-date="monthEndDate"
                :display-text="dateDisplayText"
                @date-range-changed="onDateRangeChanged"
                @previous-date="goToPreviousPeriod"
                @next-date="goToNextPeriod"
              />
            </div>
          </div>
        </div>
      </div>

      <div class="col-md-12 p-0">
        <div class="tab-content" id="myTabContent">
          <div class="expand-list">
            <a href="javascript:;" class="expand-list-btn justify-content-center align-items-center">
              <i class="icon-solid arrow-solid-left text-white" style="font-size: 9pt"></i>
            </a>
          </div>
          <div id="UserTrackingreport" class="tab-pane" :class="{ 'active show': activeKey == 0 }"
            v-if="activeKey == 0">
            <UserTrackingreport 
              :fromDate="formatDateForAPI(monthStartDate)" 
              :ToDate="formatDateForAPI(monthEndDate)"
              :displayText="dateDisplayText">
            </UserTrackingreport>
          </div>
          <div id="ExceedTimeReport" class="tab-pane" :class="{ 'active show': activeKey == 1 }" v-if="activeKey == 1">
            <ExceedTimeReport 
              :fromDate="formatDateForAPI(monthStartDate)" 
              :ToDate="formatDateForAPI(monthEndDate)"
              :displayText="dateDisplayText">
            </ExceedTimeReport>
          </div>
          <div id="LateEmployee" class="tab-pane" :class="{ 'active show': activeKey == 2 }" v-if="activeKey == 2">
            <Unproductive></Unproductive>
            <LateEmployees 
              :fromDate="formatDateForAPI(monthStartDate)" 
              :ToDate="formatDateForAPI(monthEndDate)"
              :displayText="dateDisplayText">
            </LateEmployees>
          </div>
          <div id="UnproductiveApp" class="tab-pane" :class="{ 'active show': activeKey == 3 }" v-if="activeKey == 3">
            <UnproductiveApp 
              :fromDate="formatDateForAPI(monthStartDate)" 
              :ToDate="formatDateForAPI(monthEndDate)"
              :displayText="dateDisplayText">
            </UnproductiveApp>
          </div>
          <div id="Ideltime" class="tab-pane" :class="{ 'active show': activeKey == 4 }" v-if="activeKey == 4">
            <Ideltime 
              :fromDate="formatDateForAPI(monthStartDate)" 
              :ToDate="formatDateForAPI(monthEndDate)"
              :displayText="dateDisplayText">
            </Ideltime>
          </div>
          <div id="AppWebsiteUsage" class="tab-pane" :class="{ 'active show': activeKey == 5 }" v-if="activeKey == 5">
            <AppWebsiteUsage 
              :fromDate="formatDateForAPI(monthStartDate)" 
              :ToDate="formatDateForAPI(monthEndDate)"
              :displayText="dateDisplayText">
            </AppWebsiteUsage>
          </div>
          <div id="ProductCountReport" class="tab-pane" :class="{ 'active show': activeKey == 6 }"
            v-if="activeKey == 6">
            <Category 
              :fromDate="formatDateForAPI(monthStartDate)" 
              :ToDate="formatDateForAPI(monthEndDate)"
              :displayText="dateDisplayText">
            </Category>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-designer.min';
import '@boldreports/javascript-reporting-controls/Scripts/bold.report-viewer.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.bulletgraph.min';
import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.chart.min';
import UserTrackingreport from "../TimerReports/UserTrackingreport.vue";
import ExceedTimeReport from "../TimerReports/ExceedTimeReport.vue";
import LateEmployees from "../TimerReports/LateEmployees.vue";
import UnproductiveApp from "../TimerReports/UnproductiveApp.vue";
import Ideltime from "../TimerReports/Ideltime.vue";
import AppWebsiteUsage from "../TimerReports/AppWebsiteUsage.vue";
import Category from "../TimerReports/Category.vue";
import DateRangeSelector from "../../components/Common/DateRangeSelector.vue";
import moment from 'moment';

export default {
  components: {
    UserTrackingreport,
    ExceedTimeReport,
    LateEmployees,
    UnproductiveApp,
    Ideltime,
    AppWebsiteUsage,
    Category,
    DateRangeSelector
  },
  data() {
    const today = new Date();
    const startDate = new Date(today.getFullYear(), today.getMonth(), 1);
    const endDate = new Date(today.getFullYear(), today.getMonth() + 1, 0);
    
    return {
      activeKey: 0,
      tabNames: [
        "UserTrackingReport",
        "ExceededTimeReport", 
        "LateEmployees",
        "UnproductiveAppsReport",
        "IdleTimeReport",
        "AppwebsiteusageReport",
        "CategoryReport"
      ],
      searchQuery: "",
      monthStartDate: startDate,
      monthEndDate: endDate,
      dateSpan: "thisMonth",
      dateDisplayText: ""
    };
  },
  mounted() {
    // Check for tab in route after component is mounted
    this.initializeTabFromRoute();
    this.calculateDateRange("thisMonth");
  },
  
  watch: {
    // Watch for route changes (e.g., browser back/forward)
    '$route'(to, from) {
      if (to.path === '/TimerReports/Index') {
        this.initializeTabFromRoute();
      }
    }
  },
  computed: {
    filteredTabs() {
      if (!this.searchQuery) {
        return this.tabNames.map((name, index) => ({ name, index, icon: this.getTabIcon(name) }));
      }
      const query = this.searchQuery.toLowerCase();
      return this.tabNames
        .map((name, index) => ({ name, index, icon: this.getTabIcon(name) }))
        .filter(tab => this.$t(tab.name).toLowerCase().includes(query));
    },
    activeTabName() {
      return this.tabNames[this.activeKey];
    }
  },
  methods: {
    formatDateForAPI(date) {
      if (!date) return '';
      return moment(date).format('YYYY-MM-DD');
    },

    calculateDateRange(dateSpan) {
      const today = new Date();
      let startDate, endDate, displayText;

      switch (dateSpan.toLowerCase()) {
        case "today":
          startDate = new Date(today);
          endDate = new Date(today);
          displayText = `${this.$t("Today")} (${this.formatDisplayDate(startDate)} - ${this.formatDisplayDate(endDate)})`;
          break;
        
        case "yesterday":
          startDate = new Date(today);
          startDate.setDate(today.getDate() - 1);
          endDate = new Date(startDate);
          displayText = `${this.$t("Yesterday")} (${this.formatDisplayDate(startDate)} - ${this.formatDisplayDate(endDate)})`;
          break;
        
        case "thisweek":
          // Start of week (Sunday)
          startDate = new Date(today);
          startDate.setDate(today.getDate() - today.getDay());
          // End of week (Saturday)
          endDate = new Date(startDate);
          endDate.setDate(startDate.getDate() + 6);
          displayText = `${this.$t("thisWeek")} (${this.formatDisplayDate(startDate)} - ${this.formatDisplayDate(endDate)})`;
          break;
        
        case "lastweek":
          // Start of last week (Sunday of last week)
          startDate = new Date(today);
          startDate.setDate(today.getDate() - today.getDay() - 7);
          // End of last week (Saturday of last week)
          endDate = new Date(startDate);
          endDate.setDate(startDate.getDate() + 6);
          displayText = `${this.$t("LastWeek")} (${this.formatDisplayDate(startDate)} - ${this.formatDisplayDate(endDate)})`;
          break;
        
        case "thismonth":
          startDate = new Date(today.getFullYear(), today.getMonth(), 1);
          endDate = new Date(today.getFullYear(), today.getMonth() + 1, 0);
          displayText = `${this.$t("thisMonth")} (${this.formatDisplayDate(startDate)} - ${this.formatDisplayDate(endDate)})`;
          break;
        
        case "lastmonth":
          startDate = new Date(today.getFullYear(), today.getMonth() - 1, 1);
          endDate = new Date(today.getFullYear(), today.getMonth(), 0);
          displayText = `${this.$t("LastMonth")} (${this.formatDisplayDate(startDate)} - ${this.formatDisplayDate(endDate)})`;
          break;
        
        case "all":
          startDate = new Date(2000, 0, 1);
          endDate = new Date(2100, 0, 1);
          displayText = this.$t("AllTime");
          break;
        
        default:
          startDate = new Date(today.getFullYear(), today.getMonth(), 1);
          endDate = new Date(today.getFullYear(), today.getMonth() + 1, 0);
          displayText = `${this.$t("thisMonth")} (${this.formatDisplayDate(startDate)} - ${this.formatDisplayDate(endDate)})`;
      }

      this.monthStartDate = startDate;
      this.monthEndDate = endDate;
      this.dateDisplayText = displayText;
      this.dateSpan = dateSpan.toLowerCase();
      
      console.log('Date Range Selected:', {
        span: dateSpan,
        from: this.formatDateForAPI(startDate),
        to: this.formatDateForAPI(endDate),
        display: displayText
      });
    },

    onDateRangeChanged({ dateSpan, startDate, endDate, displayText }) {
      console.log('DateRangeChanged event:', { dateSpan, startDate, endDate, displayText });
      
      if (dateSpan === 'custom') {
        // For custom dates, use the dates provided directly
        this.monthStartDate = startDate;
        this.monthEndDate = endDate;
        this.dateDisplayText = displayText;
        this.dateSpan = dateSpan;
      } else {
        // For predefined ranges, recalculate dates based on the selected range
        this.calculateDateRange(dateSpan);
      }
    },

    goToPreviousPeriod() {
      console.log('Going to previous period');
      const { startDate, endDate } = this.getPreviousPeriod();
      this.monthStartDate = startDate;
      this.monthEndDate = endDate;
      this.updateDisplayText();
    },

    goToNextPeriod() {
      console.log('Going to next period');
      const { startDate, endDate } = this.getNextPeriod();
      
      // Don't allow future dates
      const today = new Date();
      if (endDate > today) {
        console.log('Cannot go to future dates');
        return;
      }
      
      this.monthStartDate = startDate;
      this.monthEndDate = endDate;
      this.updateDisplayText();
    },

    getPreviousPeriod() {
      const start = new Date(this.monthStartDate);
      const end = new Date(this.monthEndDate);
      
      let newStart, newEnd;
      
      if (this.dateSpan === 'day' || this.dateSpan === 'today' || this.dateSpan === 'yesterday') {
        // Move back by 1 day
        newStart = new Date(start);
        newStart.setDate(start.getDate() - 1);
        newEnd = new Date(end);
        newEnd.setDate(end.getDate() - 1);
      } else if (this.dateSpan === 'week') {
        // Move back by 1 week
        newStart = new Date(start);
        newStart.setDate(start.getDate() - 7);
        newEnd = new Date(end);
        newEnd.setDate(end.getDate() - 7);
      } else {
        // Move back by 1 month
        newStart = new Date(start.getFullYear(), start.getMonth() - 1, 1);
        newEnd = new Date(start.getFullYear(), start.getMonth(), 0);
      }
      
      return { startDate: newStart, endDate: newEnd };
    },

    getNextPeriod() {
      const start = new Date(this.monthStartDate);
      const end = new Date(this.monthEndDate);
      
      let newStart, newEnd;
      
      if (this.dateSpan === 'day' || this.dateSpan === 'today' || this.dateSpan === 'yesterday') {
        // Move forward by 1 day
        newStart = new Date(start);
        newStart.setDate(start.getDate() + 1);
        newEnd = new Date(end);
        newEnd.setDate(end.getDate() + 1);
      } else if (this.dateSpan === 'week') {
        // Move forward by 1 week
        newStart = new Date(start);
        newStart.setDate(start.getDate() + 7);
        newEnd = new Date(end);
        newEnd.setDate(end.getDate() + 7);
      } else {
        // Move forward by 1 month
        newStart = new Date(start.getFullYear(), start.getMonth() + 1, 1);
        newEnd = new Date(start.getFullYear(), start.getMonth() + 2, 0);
      }
      
      return { startDate: newStart, endDate: newEnd };
    },

    updateDisplayText() {
      const start = this.formatDisplayDate(this.monthStartDate);
      const end = this.formatDisplayDate(this.monthEndDate);
      
      let rangeText = '';
      switch (this.dateSpan) {
        case 'today':
        case 'yesterday':
          rangeText = this.$t('Custom');
          break;
        case 'thisweek':
        case 'lastweek':
          rangeText = this.$t('Week');
          break;
        case 'thismonth':
        case 'lastmonth':
          rangeText = this.$t('Month');
          break;
        default:
          rangeText = this.$t('Custom');
      }
      
      this.dateDisplayText = `${rangeText} (${start} - ${end})`;
    },

    formatDisplayDate(date) {
      if (!date) return '';
      return moment(date).format('MM/DD/YYYY');
    },

    getTabIcon(name) {
      switch (name) {
        case "UserTrackingReport":
          return "fa fa-calendar";
        case "ExceededTimeReport":
          return "fa fa-clock-o";
        case "LateEmployees":
          return "fa fa-user-circle-o";
        case "UnproductiveAppsReport":
          return "fa fa-info-circle";
        case "IdleTimeReport":
          return "fa fa-clock-o";
        case "AppwebsiteusageReport":
          return "fa fa-desktop";
        case "CategoryReport":
          return "fa fa-file-text";
        default:
          return "";
      }
    },

    activateTab(index) {
      if (index < 0 || index >= this.tabNames.length) {
        return; // Invalid index
      }
      
      this.activeKey = index;
      
      // Update URL with tab name
      const tabName = this.tabNames[index];
      const encodedTabName = this.encodeTabName(tabName);
      
      // Only update route if it's different to avoid unnecessary navigation
      if (this.$route.query.tab !== encodedTabName) {
        this.$router.push({
          path: '/TimerReports/Index',
          query: { tab: encodedTabName }
        }).catch(err => {
          // Ignore navigation duplicated errors
          if (err.name !== 'NavigationDuplicated') {
            console.error('Navigation error:', err);
          }
        });
      }
    },
    
    // Encode tab name for URL (replace spaces and special chars)
    encodeTabName(tabName) {
      return encodeURIComponent(tabName);
    },
    
    // Decode tab name from URL
    decodeTabName(encodedName) {
      try {
        return decodeURIComponent(encodedName);
      } catch (e) {
        return encodedName; // Return as-is if decoding fails
      }
    },
    
    // Initialize tab from route query parameter
    initializeTabFromRoute() {
      if (this.tabNames.length === 0) {
        return; // Wait for tabs to load
      }
      
      const tabParam = this.$route.query.tab;
      
      if (tabParam) {
        const decodedTabName = this.decodeTabName(tabParam);
        const tabIndex = this.tabNames.findIndex(name => name === decodedTabName);
        
        if (tabIndex !== -1) {
          // Tab found, activate it
          this.activeKey = tabIndex;
        } else {
          // Tab not found, fallback to first tab and update URL
          this.activeKey = 0;
          const firstTabName = this.encodeTabName(this.tabNames[0]);
          this.$router.replace({
            path: '/TimerReports/Index',
            query: { tab: firstTabName }
          }).catch(() => {});
        }
      } else {
        // No tab in URL, activate first tab and add it to URL
        if (this.tabNames.length > 0) {
          this.activeKey = 0;
          const firstTabName = this.encodeTabName(this.tabNames[0]);
          this.$router.replace({
            path: '/TimerReports/Index',
            query: { tab: firstTabName }
          }).catch(() => {});
        }
      }
    }
  }
};
</script>

<style>
.customCol .btn-secondary {
  background: none;
  border: none;
  padding: 0;
}

.customCol .timedate .form-control {
  background: #138496;
  border-color: #138496;
  color: #fff;
}

.customCol .timedate span.input-group-text {
  background: #138496;
  border-color: #138496;
  color: #fff;
}

#spanDateRange {
  padding: 0 10px;
  display: inline-block;
  min-width: 150px;
}
</style>